def count_strings(n, p, q, r):
    # dp[i][j][k] = count of strings of length i with j a's and k b's
    # c's used = i - j - k
    dp = {}

    def solve(length, a_used, b_used):
        c_used = length - a_used - b_used
        if c_used < 0 or a_used > p or b_used > q or c_used > r:
            return 0
        if length == 0:
            return 1
        if (length, a_used, b_used) in dp:
            return dp[(length, a_used, b_used)]
        res = (solve(length - 1, a_used + 1, b_used) +   # place 'a'
               solve(length - 1, a_used, b_used + 1) +   # place 'b'
               solve(length - 1, a_used, b_used))        # place 'c'
        dp[(length, a_used, b_used)] = res
        return res

    return solve(n, 0, 0)

# Example: strings of length 3 with at most 1 'a', 1 'b', 1 'c'
print(count_strings(3, 1, 1, 1))  # 6 (all permutations of abc)

def find_longest_word(s, dictionary):
    def is_subsequence(word, string):
        w_ptr = 0
        for char in string:
            if w_ptr < len(word) and char == word[w_ptr]:
                w_ptr += 1
        return w_ptr == len(word)

    # Sort by length desc, then lexicographically asc for tiebreaking
    dictionary.sort(key=lambda x: (-len(x), x))

    for word in dictionary:
        if is_subsequence(word, s):
            return word
    return ''

# Example
