# Output: 'apple'

def find_two_non_repeating(arr):
    # Step 1: XOR all elements to get A XOR B
    xor_all = 0
    for num in arr:
        xor_all ^= num

    # Step 2: Find the rightmost set bit (A and B differ here)
    rightmost_set_bit = xor_all & (-xor_all)

    # Step 3: Partition into two groups and XOR each group
    a, b = 0, 0
    for num in arr:
        if num & rightmost_set_bit:
            a ^= num
        else:
            b ^= num

    return a, b

print(find_two_non_repeating([2, 3, 7, 9, 11, 2, 3, 11]))  # (7, 9)

def find_celebrity(n, knows):
    # Elimination phase using two pointers
    candidate = 0
    for i in range(1, n):
        if knows(candidate, i):
            candidate = i  # candidate knows i, so candidate is not celebrity

    # Verification phase
    for i in range(n):
        if i == candidate:
            continue
        if knows(candidate, i) or not knows(i, candidate):
            return -1  # no celebrity found

    return candidate

