def allocate_pages(pages, m):
    if m > len(pages):
        return -1  # more students than books

    def can_allocate(max_pages):
        students = 1
        current = 0
        for p in pages:
            if p > max_pages:
                return False  # single book exceeds limit
            if current + p > max_pages:
                students += 1
                current = p
                if students > m:
                    return False
            else:
                current += p
        return True

    lo, hi = max(pages), sum(pages)
    result = hi
    while lo <= hi:
        mid = (lo + hi) // 2
        if can_allocate(mid):
            result = mid
            hi = mid - 1  # try to minimize further
        else:
            lo = mid + 1
    return result

