def word_break(s, word_dict):
    word_set = set(word_dict)
    memo = {}

    def can_break(start):
        if start == len(s):
            return True
        if start in memo:
            return memo[start]
        for end in range(start + 1, len(s) + 1):
            if s[start:end] in word_set and can_break(end):
                memo[start] = True
                return True
        memo[start] = False
        return False

    return can_break(0)

# Iterative DP version
def word_break_dp(s, word_dict):
    word_set = set(word_dict)
    n = len(s)
    dp = [False] * (n + 1)
    dp[0] = True
    for i in range(1, n + 1):
        for j in range(i):
            if dp[j] and s[j:i] in word_set:
                dp[i] = True
                break
    return dp[n]

print(word_break('leetcode', ['leet', 'code']))  # True

import heapq

class MedianFinder:
    def __init__(self):
        self.lo = []  # max-heap (negate values since Python has min-heap)
        self.hi = []  # min-heap

    def add_num(self, num):
        # Push to max-heap (lower half)
        heapq.heappush(self.lo, -num)

        # Ensure max(lo) <= min(hi)
        if self.lo and self.hi and (-self.lo[0]) > self.hi[0]:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))

        # Balance sizes: lo can have at most 1 more element than hi
        if len(self.lo) > len(self.hi) + 1:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))
        elif len(self.hi) > len(self.lo):
            heapq.heappush(self.lo, -heapq.heappop(self.hi))

    def find_median(self):
        if len(self.lo) == len(self.hi):
            return (-self.lo[0] + self.hi[0]) / 2.0
        return float(-self.lo[0])

mf = MedianFinder()
for x in [5, 3, 8, 1, 9]:
    mf.add_num(x)
    print(mf.find_median())
